mapper.select:
/* FAQ 목록 조회 */ select a.faq_idx, a.question, a.answer, b.faq_cate_idx, b.faq_cate_name from tb_faq a, tb_faq_category b where a.faq_cate_idx = b.faq_cate_idx and a.del_yn = 'N'
and a.faq_cate_idx = #{cateIdx}
and (a.question like concat('%', #{search}, '%') or a.answer like concat('%', #{search}, '%'))
order by a.reg_date desc

/* FAQ 목록 조회 */
select 
	count(*) as listCnt
from(
	select 
		a.faq_idx, a.question, a.answer, b.faq_cate_idx, b.faq_cate_name
	from tb_faq a, tb_faq_category b
	where a.faq_cate_idx = b.faq_cate_idx
	and a.del_yn = 'N'
	
	and a.faq_cate_idx = #{cateIdx}
	
	
	and (a.question like concat('%', #{search}, '%') or a.answer like concat('%', #{search}, '%'))
	
) f_tb

/* FAQ 카테고리 한건 조회 */
select
	faq_cate_idx, faq_cate_name
from tb_faq_category
where faq_cate_idx = #{faqCateIdx}

/* FAQ 한건 조회 */
select
	faq_idx, faq_cate_idx, question, replace(answer, '<br/>', '\\n') answer
from tb_faq
where del_yn = 'N'
and faq_idx = #{faqIdx}

mapper.insert:
/* FAQ 카테고리 등록 */ insert into tb_faq_category (
faq_cate_name, /* 카테고리명 */ reg_uid, /* 등록자ID */ reg_date /* 등록일시 */ ) values (
#{faqCateName }, #{regUid }, now() )

/* FAQ 등록 */ insert into tb_faq (
faq_cate_idx, /* 카테고리식별자 */ question, /* 질문 */ answer, /* 답변 */ del_yn, /* 삭제여부(Y:예,N:아니오) */ reg_uid, /* 등록자ID */ reg_date /* 등록일시 */ ) values (
#{faqCateIdx }, #{question }, #{answer }, 'N', #{regUid }, now() )

mapper.delete:
/* FAQ 카테고리 삭제 */
delete from tb_faq_category
where faq_cate_idx = #{faqCateIdx }
